  @tailrec
  private def unpack(s: String, to: Vector[String]): Vector[String] =
    if (s.length > 6)
      unpack(s.drop(6), to :+ s.take(6))
    else
      to :+ s

  private val colourArrays: Vector[Vector[String]] =
    colourStrings.map(unpack(_, Vector.empty))

  /**
   * @param one Colour when noOfColours ≤ 1.
   * @param over Colour to use when noOfColours = max and a requested colour is over the max (and this unavailable).
   * @return A function that returns a colour string for a given colour index in [0,noOfColours).
   */
  def apply(one: String, noOfColours: Int, over: String): Int => String = {
    val i = noOfColours - 2 // ∴ colourArrays[0] = 2 colours
    if (i < 0)
      _ => one
    else {
      val colours = colourArrays.getOrElse(i, colourArrays.last)
      j => colours.getOrElse(j, over)
    }
  }
